    36→	return GrafanaPrefix + p.ServiceID + "_" + p.Secret
    37→}
    38→
    39→func (p *PrefixedKey) CalculateChecksum() string {
    40→	checksum := crc32.ChecksumIEEE([]byte(p.key()))
    41→	//checksum to []byte
    42→	checksumBytes := make([]byte, 4)
    43→	checksumBytes[0] = byte(checksum)
    44→	checksumBytes[1] = byte(checksum >> 8)
    45→	checksumBytes[2] = byte(checksum >> 16)
    46→	checksumBytes[3] = byte(checksum >> 24)
    47→
    48→	return hex.EncodeToString(checksumBytes)
    49→}
    50→
    51→func (p *PrefixedKey) String() string {
    52→	return p.key() + "_" + p.Checksum
    53→}
    54→
    55→func New(serviceID string) (KeyGenResult, error) {
    56→	result := KeyGenResult{}
    57→
    58→	secret, err := util.GetRandomString(32)
    59→	if err != nil {
    60→		return result, err
    61→	}
    62→
    63→	key := PrefixedKey{ServiceID: serviceID, Secret: secret, Checksum: ""}
    64→	key.Checksum = key.CalculateChecksum()
    65→
    66→	result.HashedKey, err = key.Hash()
    67→	if err != nil {
    68→		return result, err
    69→	}
    70→
    71→	result.ClientSecret = key.String()
    72→
    73→	return result, nil
    74→}
    75→
    76→func Decode(keyString string) (*PrefixedKey, error) {
    77→	if !strings.HasPrefix(keyString, GrafanaPrefix) {
    78→		return nil, ErrInvalidApiKey
    79→	}
    80→
    81→	parts := strings.Split(keyString, "_")
    82→	if len(parts) != 3 {
    83→		return nil, ErrInvalidApiKey
    84→	}
    85→
    86→	key := &PrefixedKey{
    87→		ServiceID: strings.TrimPrefix(parts[0], GrafanaPrefix),
    88→		Secret:    parts[1],
    89→		Checksum:  parts[2],
    90→	}
    91→	if key.CalculateChecksum() != key.Checksum {
    92→		return nil, ErrInvalidApiKey
    93→	}
    94→
    95→	return key, nil
    96→}
